={{ (function(){
  const b = $json.body || $json;
  const email = (b.email || '').toLowerCase();
  const notes = (b.notes || '').toLowerCase();
  const business = (b.businessName || '').toLowerCase();
  const phone = (b.phone || '').replace(/[^0-9+]/g, '');
  if (email === 'health-monitor@example.com' || email === 'audit@example.com' || email.endsWith('@example.com')) return false;
  if (notes.includes('audit-test') || notes.includes('health-monitor') || notes.includes('please ignore')) return false;
  if (business.startsWith('test') || business.startsWith('audit') || business.startsWith('health-monitor')) return false;
  if (!phone || phone.length < 10) return false;
  return true;
