const raw = $input.item.json;
// Format Lead Data passes through the raw webhook envelope (headers/body/...). Pull from .body.
const lead = raw.body || raw;
const ownerName = (lead.ownerName || '').trim();
const firstName = ownerName.split(/\s+/)[0] || ownerName || 'there';
// Normalize phone to E.164 (US default).
let phone = String(lead.phone || '').replace(/[^0-9+]/g, '');
if (!phone.startsWith('+')) {
  if (phone.length === 10) phone = '+1' + phone;
  else if (phone.length === 11 && phone.startsWith('1')) phone = '+' + phone;
}

const payload = {
  // example.com client agent (per Goal B brief)
  agent_id: 'agent_7801kqqqhjmcfdsa1m2a8t9w6t5c',
  // Outbound caller has a default phone number ID; only override if needed.
  phone: phone,
  customer_name: ownerName || (lead.businessName || 'Caller'),
  customer_id: 'lead_' + (lead.businessName || 'unknown').toLowerCase().replace(/[^a-z0-9]/g, '-').slice(0, 60) + '_' + Date.now(),
  account_type: 'trial',
  call_purpose: 'outbound qualification — fresh inbound web lead',
  custom_variables: {
    customer_first_name: firstName,
    business_name: lead.businessName || 'Unknown',
    industry: lead.industry || 'Unknown',
    requested_package: lead.package || 'unspecified',
    contact_email: lead.email || '',
    lead_source: 'example.com lead intake form',
    framing_note: 'Treat this caller as a FRESH inbound lead who just submitted the example.com pricing form. This is qualification, not a callback confirmation. The caller has NOT been contacted before. Open with: identify yourself, acknowledge their form submission, then qualify (BANT). Do NOT ask "calling you back" or "did we connect earlier" — they did not request a callback.',
    submitted_at: lead.timestamp || new Date().toISOString(),
    lead_notes: (lead.notes || '').slice(0, 500)
  },
  first_message_override: 'Hi ' + firstName + ', this is client from example Systems. I saw you just submitted our pricing form for ' + (lead.businessName || 'your business') + '. I have a quick minute to walk you through how the 24/7 Filter would work for ' + (lead.industry || 'your industry') + ' — does now work, or would you rather schedule a deeper conversation?'
};

return { json: payload };

const item = $input.item.json;
const lead = item.body || item;
const now = Date.now();
const staticData = $getWorkflowStaticData('global');
staticData.rateDedupe = staticData.rateDedupe || { seen: {}, buckets: {} };
const state = staticData.rateDedupe;

for (const [key, expiresAt] of Object.entries(state.seen)) {
  if (Number(expiresAt) <= now) delete state.seen[key];
}
for (const [key, bucket] of Object.entries(state.buckets)) {
  if (!bucket || Number(bucket.resetAt) <= now) delete state.buckets[key];
}

const clean = (value) => String(value || '').trim().toLowerCase();
const email = clean(lead.email);
const businessName = clean(lead.businessName);
const phone = String(lead.phone || '').replace(/[^0-9+]/g, '');
const packageId = clean(lead.package);
const notes = clean(lead.notes).slice(0, 160);
const dedupeKey = [packageId, email, businessName, phone, notes].join('|');
const rateKey = email || phone || businessName || 'unknown';
const windowMs = 15 * 60 * 1000;
const maxPerWindow = 2;

const bucket = state.buckets[rateKey] || { count: 0, resetAt: now + windowMs };
bucket.count += 1;
state.buckets[rateKey] = bucket;

let allowed = true;
let reason = '';
const synthetic = email === 'health-monitor@example.com' || email === 'audit@example.com' || email.endsWith('@example.com') || email.endsWith('@example.invalid') || businessName.startsWith('test') || businessName.startsWith('audit') || businessName.startsWith('health-monitor') || notes.includes('audit-test') || notes.includes('health-monitor') || notes.includes('please ignore');
if (synthetic) {
  allowed = false;
  reason = 'synthetic_or_monitor_traffic';
} else if (state.seen[dedupeKey]) {
  allowed = false;
  reason = 'duplicate_lead_payload';
} else if (bucket.count > maxPerWindow) {
  allowed = false;
  reason = 'lead_rate_limited';
}

if (allowed) state.seen[dedupeKey] = now + windowMs;

return {
  json: {
    ...item,
    rate_limit: {
      allowed,
      reason,
      rateKey,
      dedupeKey,
      windowSeconds: Math.floor(windowMs / 1000),
      count: bucket.count,
      max: maxPerWindow,
    },
  },
};
